
import { defineComponent, inject, onMounted, reactive, ref, toRaw } from "vue";
import Signatory from "./Contract/Signatory.vue";
import { sealListOfQys, createbycategory } from "@/server/http/api/seal";
export default defineComponent({
  props: ["sealType", "entrustId", "userInfo"],
  emits: ["addCurrent_emit"],
  components: {
    Signatory,
  },
  setup(props, { emit }) {
    const loading = ref(false);
    const Signatory = ref();
    let sealListOptions = ref([]);
    const init: any = inject("init");

    const formRef = ref();
    const formState: any = reactive({
      subject: "",
      category: "ELECTRONIC",
      send: true,
      tenantName: "河南省公路工程试验检测中心有限公司",
      creatorName: "",
      creatorContact: "",
    });
    onMounted(() => {
      sealList("ELECTRONIC");
      formState.creatorName = props.userInfo.name;
      formState.creatorContact = props.userInfo.mobile;
    });
    const rules = {
      subject: [
        {
          required: true,
          message: "请输入",
          trigger: "blur",
        },
      ],
      send: [
        {
          required: true,
          message: "请输入",
          trigger: "blur",
          type: "boolean",
        },
      ],
      category: [
        {
          required: true,
          message: "请输入",
          trigger: "blur",
        },
      ],
      tenantName: [
        {
          required: true,
          message: "请输入",
          trigger: "blur",
        },
      ],
      creatorName: [
        {
          required: true,
          message: "请输入",
          trigger: "blur",
        },
      ],
      creatorContact: [
        {
          required: true,
          message: "请输入",
          trigger: "blur",
        },
        {
          pattern:
            /^(13[0-9]|14[01456879]|15[0-35-9]|16[2567]|17[0-8]|18[0-9]|19[0-35-9])\d{8}$/,
          message: "手机号不合法",
          trigger: "blur",
        },
      ],
    };
    const onSubmit = () => {
      formRef.value
        .validate()
        .then(() => {
          Signatory.value
            .submitForm()
            .then(() => {
              loading.value = true;
              //console.log(formState, Signatory.value.dynamicValidateForms);
              let SignatoryFroms: any = [];
              Signatory.value.dynamicValidateForms.forEach(
                (item: any, index: any) => {
                  SignatoryFroms.push({
                    serialNo: item.value.serialNo,
                    tenantName: item.value.tenantName,
                    tenantType: item.value.tenantType,
                    actions: [],
                  });
                  item.value.signatories.forEach((val: any, i: any) => {
                    SignatoryFroms[index].actions.push({
                      type: val.value.type,
                      name: val.value.name,
                      serialNo: val.value.serialNo,
                      sealIds: JSON.stringify(val.value.sealIds),
                      actionOperators: [],
                    });
                    val.value.PersonSign.forEach((obj: any) => {
                      SignatoryFroms[index].actions[i].actionOperators.push({
                        operatorName: obj.value.operatorName,
                        operatorContact: obj.value.operatorContact,
                      });
                    });
                  });
                }
              );
              //console.log(JSON.stringify(SignatoryFroms));
              delete formState.category;
              createbycategory({
                entrustId: props.entrustId,
                ...formState,
                signatories: SignatoryFroms,
              }).then((res: any) => {
                //console.log(res);
                if (res.data.code === 200) {
                  emit("addCurrent_emit");
                  init();
                }
                loading.value = true;
              });
            })
            .catch((err: any) => {
              loading.value = true;
            });
        })
        .catch((error: any) => {
          //console.log("error", error);
        });
    };

    const sealList = (value: any) => {
      //console.log(value);
      sealListOfQys({
        sealType: props.sealType,
        category: value,
        companyName: formState.tenantName,
      }).then((res: any) => {
        sealListOptions.value = res.data.data.list.map((item: any) => {
          return { label: item.name, value: item.id };
        });
      });
    };

    return {
      labelCol: { span: 6 },
      wrapperCol: { span: 14 },
      formState,
      onSubmit,
      formRef,
      rules,
      Signatory,
      sealList,
      sealListOptions,
      loading,
    };
  },
});
