
import { MinusCircleOutlined, PlusOutlined } from "@ant-design/icons-vue";
import { ValidateErrorEntity } from "ant-design-vue/es/form/interface";
import { defineComponent, reactive, ref, UnwrapRef } from "vue";
import { nanoid } from "nanoid";

export default defineComponent({
  components: {
    MinusCircleOutlined,
    PlusOutlined,
  },
  props: ["sealListOptions"],
  setup() {
    const formRef = ref();
    let dynamicValidateForms: any = ref([
      {
        value: {
          tenantType: "COMPANY",
          tenantName: "河南省公路工程试验检测中心有限公司",
          serialNo: "1",
          signatories: [
            {
              value: {
                type: "CORPORATE",
                name: "河南省公路工程试验检测中心有限公司",
                serialNo: "1",
                sealIds: [],
                PersonSign: [
                  {
                    value: {},
                    key: nanoid(),
                  },
                ],
              },
              key: nanoid(),
            },
          ],
        },
        key: nanoid(),
      },
    ]);
    const formItemLayout = {
      labelCol: {
        xs: { span: 24 },
        sm: { span: 4 },
      },
      wrapperCol: {
        xs: { span: 24 },
        sm: { span: 20 },
      },
    };
    const formItemLayoutWithOutLabel = {
      wrapperCol: {
        xs: { span: 24, offset: 0 },
        sm: { span: 20, offset: 4 },
      },
    };

    const submitForm = () => {
      return formRef.value.validate();
      // .then(() => {
      //   //console.log("values", dynamicValidateForms);
      // })
      // .catch((error: ValidateErrorEntity<any>) => {
      //   //console.log("error", error);
      // });
    };
    const resetForm = () => {
      formRef.value.resetFields();
    };
    const removeDomain = (item: any) => {
      let index = dynamicValidateForms.value.indexOf(item);
      //console.log(index);

      if (index !== -1) {
        dynamicValidateForms.value.splice(index, 1);
      }
    };
    const addDomain = () => {
      dynamicValidateForms.value.push({
        value: {
          tenantType: "COMPANY",
          tenantName: "河南省公路工程试验检测中心有限公司",
          serialNo: "1",
          signatories: [
            {
              value: {
                type: "CORPORATE",
                name: "河南省公路工程试验检测中心有限公司",
                serialNo: "1",
                sealIds: [],
                PersonSign: [
                  {
                    value: {},
                    key: nanoid(),
                  },
                ],
              },
              key: nanoid(),
            },
          ],
        },
        key: nanoid(),
      });
    };
    const addActionSign = (index: number) => {
      dynamicValidateForms.value[index].value.signatories.push({
        value: {
          type: "CORPORATE",
          name: "河南省公路工程试验检测中心有限公司",
          serialNo: "1",
          sealIds: [],
          PersonSign: [
            {
              value: {},
              key: nanoid(),
            },
          ],
        },
        key: nanoid(),
      });
    };
    const addPersonSign = (index: number, index_one: number) => {
      dynamicValidateForms.value[index].value.signatories[
        index_one
      ].value.PersonSign.push({
        value: {},
        key: nanoid(),
      });
    };
    return {
      formRef,
      formItemLayout,
      formItemLayoutWithOutLabel,
      submitForm,
      resetForm,
      removeDomain,
      addDomain,
      dynamicValidateForms,
      labelCol: { span: 6 },
      wrapperCol: { span: 14 },
      addActionSign,
      addPersonSign,
    };
  },
});
