
import { message } from "ant-design-vue";
import { defineComponent, inject, reactive, ref, toRaw } from "vue";
import { sealApprove } from "@/server/http/api/seal";
const fileType = [
  "doc",
  "docx",
  "txt",
  "png",
  "pdf",
  "gif",
  "jpg",
  "jpeg",
  "tiff",
  "html",
  "rtf",
  "xls",
  "txt",
];
export default defineComponent({
  emits: ["addCurrent_emit"],
  props: ["entrustId"],
  setup(props, { emit }) {
    const formRef = ref();
    const init: any = inject("init");
    let loading = ref(false);
    const formState: any = reactive({
      title: "",
      fileType: "pdf",
    });
    const rules = {
      title: [
        {
          required: true,
          message: "请选择合同标题",
          trigger: "blur",
        },
      ],
    };
    const onSubmit = () => {
      let { title, fileType } = formState;
      formRef.value
        .validate()
        .then(() => {
          loading.value = true;
          sealApprove({
            entrustId: props.entrustId,
            title,
            fileType,
          })
            .then(
              (res: any) => {
                if (res.data.code === 200) {
                  init();
                  title = "";
                  fileType = "pdf";
                  emit("addCurrent_emit");
                }
                loading.value = false;
              },
              (err) => {
                loading.value = false;
                message.error(err);
              }
            )
            .catch((res) => {
              loading.value = false;
              message.error(res);
            });
        })
        .catch((error: any) => {
          //console.log("error", error);
          loading.value = false;
        });
    };
    return {
      labelCol: { span: 6 },
      wrapperCol: { span: 12 },
      formState,
      onSubmit,
      formRef,
      rules,
      fileType,
      loading,
    };
  },
});
