import http from '../http'

interface SealListOfQys {
    sealType: string
    category: string
    companyName: string
}
// 契约锁所需印章列表
export function sealListOfQys(options: SealListOfQys) {
    return http.get('/jkyErp/report/sealListOfQys', options)
}

interface SealApprove {
    entrustId: number
    title: string
    fileType: string
}
// 契约锁-合同发起
export function sealApprove(options: SealApprove) {
    return http.get('/jkyErp/report/sealApprove', options)
}

// 契约锁-合同创建
export function createbycategory(options: any) {
    return http.post('/jkyErp/report/createbycategory', options)
}

interface Signurl {
    entrustId: number
    contractId: number
    tenantName: string
    tenantType: string
    contact: string
    expireTime: number
    receiverName: string
}

// 契约锁-合同签署
export function signurl(options: Signurl) {
    return http.post('/jkyErp/report/signurl', options)
}


interface DownloadQysFile {
    entrustId: number
    contractId: number
    name: string
    contact: string
}
// 契约锁-合同下载
export function downloadQysFile(options: DownloadQysFile) {
    return http.get('/jkyErp/report/downloadQysFile', options)
}