
import { ref, defineComponent, reactive, inject, watch, onMounted } from "vue";
import { addSeal } from "@/server/http/api/Amultitasking";
// 发起合同
import Initiate from "./AddComponents/Initiate.vue";
// 创建合同
import Contract from "./AddComponents/Contract.vue";
// 签署合同
import Sign from "./AddComponents/Sign.vue";
import { useStore } from "vuex";

export default defineComponent({
  props: ["id", "record"],
  components: {
    Initiate,
    Contract,
    Sign,
  },
  setup(props: any) {
    const init: any = inject("init");
    let current = ref(props.record.qysState * 1 - 1);
    const Contract = ref();
    let sealWidth = ref("600px");
    let wrapClassName = ref("");
    const visible = ref<boolean>(false);
    const confirmLoading = ref<boolean>(false);
    const store = useStore();
    let userInfo: any = ref({});
    onMounted(() => {
      userInfo.value = JSON.parse(store.state.userInfo);
    });
    const formState = reactive({
      sealType: [],
    });
    watch(current, (newVal) => {
      switch (newVal) {
        case 0:
          sealWidth.value = "600px";
          wrapClassName.value = "";

          break;
        case 1:
          sealWidth.value = "1200px";

          break;
        case 2:
          sealWidth.value = "600px";
          wrapClassName.value = "";

          break;
        default:
          break;
      }
    });
    function next() {
      current.value++;
    }
    const showModal = () => {
      formState.sealType = [];
      visible.value = true;
    };

    const handleOk = () => {
      //console.log(Contract);

      visible.value = false;
      confirmLoading.value = false;
    };

    function addCurrent() {
      current.value++;
    }

    return {
      visible,
      confirmLoading,
      showModal,
      handleOk,
      formState,
      current,
      addCurrent,
      sealWidth,
      wrapClassName,
      next,
      Contract,
      userInfo,
    };
  },
});
