import { defineComponent, provide, reactive, ref, toRefs, watch } from "vue";
import { sealList, addSeal } from "@/server/http/api/Amultitasking";
import CheckDetail from "./model/Reportgeneration/CheckDetail.vue";
import AddSeal from "./model/Seal/AddSeal.vue";
import PreviewCheck from "./model/Reportgeneration/PreviewCheck.vue";
import {
  getTemplateList,
  approval_download,
} from "@/server/http/api/Amultitasking";
import DownloadCheck from "@/views/ProductionManagement/Amultitasking/model/Reportgeneration/DownloadCheck.vue";

import { downloadQysFile } from "@/utils/DownLoad";
import { useStore } from "vuex";
const stateList = [
  {
    label: "合同待发起",
    value: 1,
  },
  {
    label: "合同待创建",
    value: 2,
  },
  {
    label: "合同待签署",
    value: 3,
  },
  {
    label: "合同待盖章",
    value: 4,
  },
  {
    label: "合同待下载",
    value: 5,
  },
];
export default defineComponent({
  name: "Seal",
  components: { CheckDetail, AddSeal, PreviewCheck, DownloadCheck },

  setup() {
    let searchValue = ref("");
    let state = ref(1);
    const store = useStore();
    const userInfo = ref(JSON.parse(store.state.userInfo));
    let datatList = ref([]);

    const formRef = ref();
    const formState = reactive({
      name: "",
      contact: "",
    });
    let visible = ref(false);
    const rules = {
      name: [
        {
          required: true,
          message: "请输入",
          trigger: "blur",
        },
      ],
      contact: [
        {
          required: true,
          message: "请输入",
          trigger: "blur",
        },
      ],
    };
    let searchOption = reactive({
      active: 1,
      pageNum: 1,
      pageSize: 10,
    });
    let total = ref(0);
    // 搜索函数
    function searchData() {
      sealList({
        type: searchOption.active,
        search: searchValue.value,
        pageNum: searchOption.pageNum,
        pageSize: searchOption.pageSize,
        state: state.value,
      }).then((res: any) => {
        //console.log(res);

        if (res.data.code === 200) {
          datatList.value = res.data.data.list;
          total.value = res.data.data.total;
        }
      });
    }

    // 搜索条件
    let timer: any;
    watch(searchValue, () => {
      clearTimeout(timer);
      timer = setTimeout(() => {
        searchData();
      }, 400);
    });
    watch(state, () => {
      clearTimeout(timer);
      timer = setTimeout(() => {
        searchData();
      }, 400);
    });
    // 分页搜索
    watch(
      searchOption,
      () => {
        searchData();
      },
      {
        immediate: true,
      }
    );

    provide("init", searchData);
    // 预览
    function perview() {}
    // 盖章
    function seal() {}
    function onSearch() {}

    function contractDownload() {
      //console.log(userInfo);

      formState.name = userInfo.value.name;
      formState.contact = userInfo.value.mobile;
      visible.value = true;
    }
    function handleOk(entrustmentId: any, contractId: any) {
      formRef.value
        .validate()
        .then(() => {
          visible.value = false;
          downloadQysFile({
            entrustId: entrustmentId,
            contractId,
            ...formState,
          });
        })
        .catch((error: any) => {
          //console.log("error", error);
        });
    }
    return {
      onSearch,
      searchValue,
      datatList,
      columns,
      columns1,
      perview,
      seal,
      ...toRefs(searchOption),
      total,
      stateList,
      state,
      contractDownload,
      formState,
      visible,
      rules,
      labelCol: { span: 6 },
      wrapperCol: { span: 12 },
      formRef,
      handleOk,
    };
  },
});
