
import { defineComponent, inject, onMounted, reactive, ref, toRaw } from "vue";
import { signurl } from "@/server/http/api/seal";
const tenantTypeList = [
  {
    label: "外部企业",
    value: "COMPANY",
  },
  {
    label: "个人",
    value: "PERSONAL",
  },
  {
    label: "默认",
    value: "COMPANY",
  },
];
export default defineComponent({
  emits: ["addCurrent_emit"],
  props: ["entrustId", "userInfo"],

  setup(props, { emit }) {
    const loading = ref(false);
    const init: any = inject("init");

    const formRef = ref();
    const formState: any = reactive({
      // contractId: "",
      tenantName: "河南省公路工程试验检测中心有限公司",
      tenantType: "COMPANY",
      contact: "",
      expireTime: 72,
      receiverName: "",
    });
    onMounted(() => {
      formState.receiverName = props.userInfo.name;
      formState.contact = props.userInfo.mobile;
    });
    const rules = {
      // contractId: [
      //   {
      //     required: true,
      //     message: "请输入",
      //     trigger: "blur",
      //   },
      // ],
      tenantName: [
        {
          required: true,
          message: "请输入",
          trigger: "blur",
        },
      ],
      tenantType: [
        {
          required: true,
          message: "请输入",
          trigger: "blur",
        },
      ],
      contact: [
        {
          required: true,
          message: "请输入",
          trigger: "blur",
        },
        {
          pattern:
            /^(13[0-9]|14[01456879]|15[0-35-9]|16[2567]|17[0-8]|18[0-9]|19[0-35-9])\d{8}$/,
          message: "手机号不合法",
          trigger: "blur",
        },
      ],
      expireTime: [
        {
          required: true,
          message: "请输入",
          trigger: "blur",
          type: "number",
        },
      ],
      receiverName: [
        {
          required: true,
          message: "请输入",
          trigger: "blur",
        },
      ],
    };
    const onSubmit = () => {
      formRef.value
        .validate()
        .then(() => {
          loading.value = true;
          signurl({
            entrustId: props.entrustId,
            ...formState,
          }).then((res: any) => {
            if (res.data.code === 200) {
              emit("addCurrent_emit");
              init();
            }
            loading.value = false;
          });
        })
        .catch((error: any) => {
          loading.value = false;
          //console.log("error", error);
        });
    };
    return {
      labelCol: { span: 6 },
      wrapperCol: { span: 12 },
      formState,
      onSubmit,
      formRef,
      rules,
      tenantTypeList,
      loading,
    };
  },
});
